public static readonly LlamaLibrary.Logging.LLogger Log = new("ARR", Colors.DeepPink);

private static readonly string[] TutorialWindows =
{
    "HowToNotice",
    "HowTo",
    "PlayGuide",
    "JobHudNotice",
    "ContentsTutorial",
    "RecommendList",
    "AchievementInfo",
};



        bool hasTutorialWindow = TutorialWindows
            .Any(window => RaptureAtkUnitManager.GetWindowByName(window) != null);

        if (hasTutorialWindow)
        {
            await LlamaLibrary.Helpers.GeneralFunctions.CloseHowTos();
        }

			  return false;



            uint[] wayOfQuestIds = { 65557,65558,65559,65789,66069,65881,65989,65847 };

            if (!wayOfQuestIds.Any(QuestLogManager.IsQuestCompleted))
            {
                return false;
            }

            var mobsToKill = GameObjectManager.GetObjectsOfType<BattleCharacter>()
                .OrderBy(bc => bc.Distance()).FirstOrDefault(bc => bc.InLineOfSight() && bc.IsAlive && !bc.IsFate && bc.IsActiveHuntTarget && bc.IsVisible && bc.IsTargetable && bc.ClassLevel <= Core.Me.ClassLevel +5);

            if (mobsToKill != null && mobsToKill.IsValid && !Core.Me.InCombat && (Poi.Current == null || Poi.Current.Type != PoiType.Kill))
            {
                Log.Information($"Found Target {mobsToKill.EnglishName}");
                Poi.Current = new Poi(mobsToKill, PoiType.Kill);
            }
	        return false;


var Combat = Enumerable.Range(8, 11).Append(0).Append(36);
var gearSets = GearsetManager.GearSets.Where(i => i.InUse && !Combat.Contains((int)i.Class)).ToList().OrderByDescending(i=> i.Gear.First().Item.ItemLevel);

if (gearSets.Any())
{
    gearSets.First().Activate();
    await Coroutine.Sleep(2000);
}

Logging.Write("Commencing duty.");
uint[] npcIds = { 1021261, 2006316 };
var dutyNpc = GameObjectManager.GameObjects.Where(r => r.IsTargetable && npcIds.Contains(r.NpcId)).OrderBy(r => r.Distance()).FirstOrDefault();

while (Core.Me.Location.Distance2D(dutyNpc.Location) > 1.5f)
{
	await Coroutine.Yield();
	Navigator.PlayerMover.MoveTowards(dutyNpc.Location);
}

Navigator.PlayerMover.MoveStop();
dutyNpc.Interact();
await Coroutine.Wait(5000, () => Talk.DialogOpen || DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen);

while (!(DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen))
{
	Talk.Next();
	await Coroutine.Yield();
}

await Coroutine.Wait(5000, () => DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen);

if (DifficultySelectYesNo.IsOpen)
{
	DifficultySelectYesNo.Proceed(2);
}
else if (SelectYesno.IsOpen)
{
	SelectYesno.Yes();
}
else
{
	Logging.Write("Duty window didn't open.");
	TreeRoot.Stop();
}

await Coroutine.Wait(2000, () => CommonBehaviors.IsLoading);
await Coroutine.Wait(-1, () => !CommonBehaviors.IsLoading);

while (ff14bot.Managers.QuestLogManager.InCutscene)
{
	ff14bot.RemoteAgents.AgentCutScene.Instance.PromptSkip();
	if (ff14bot.RemoteAgents.AgentCutScene.Instance.CanSkip && SelectString.IsOpen) { SelectString.ClickSlot(0); }
	if (Talk.DialogOpen) { Talk.Next(); }
	await Coroutine.Yield();
}

await Coroutine.Wait(2000, () => CommonBehaviors.IsLoading);
await Coroutine.Wait(-1, () => !CommonBehaviors.IsLoading);
await Coroutine.Wait(10000, () => !Core.Me.HasAura(1268));
Logging.Write("Duty commenced.");
await Coroutine.Sleep(1500);


var _target = GameObjectManager.GetObjectByNPCId(8488);
_target.Target();
await Coroutine.Sleep(1000);
ActionManager.DoAction(15997, Core.Target);
await Coroutine.Sleep(2000);
ActionManager.DoAction(16000, Core.Target);
await Coroutine.Sleep(2000);
